class BattleRoyaleServer:
    def __init__(self, host='localhost', port=8765):
        self.host = host
        self.port = port
        self.clients: Dict[websockets.WebSocketServerProtocol, str] = {}
        self.players: Dict[str, Player] = {}
        self.game_state = GameState({}, time.time(), 0)
