    async def handle_message(self, websocket, message):
        try:
            data = json.loads(message)
            msg_type = data.get('type')
            
            if msg_type == 'update_position':
                self.update_player_position(data)
            elif msg_type == 'filter_update':
                self.client_filters[self.clients[websocket]] = data.get('filters', {})
                
        except json.JSONDecodeError:
            logger.error("Invalid JSON message")
        except Exception as e:
            logger.error(f"Error handling message: {e}")
    
    def update_player_position(self, data):
        player_id = data.get('player_id')
        if not player_id:
            return
            
        player = self.players.get(player_id)
        if not player:
            player = Player(
                id=player_id,
                x=data.get('x', 0),
                y=data.get('y', 0),
                z=data.get('z', 0),
                health=data.get('health', 100),
                weapon=data.get('weapon', 'none'),
                team=data.get('team', 'none'),
                timestamp=time.time()
            )
            self.players[player_id] = player
        else:
            player.x = data.get('x', player.x)
            player.y = data.get('y', player.y)
            player.z = data.get('z', player.z)
            player.health = data.get('health', player.health)
            player.weapon = data.get('weapon', player.weapon)
            player.team = data.get('team', player.team)
